// Initialize application on window load
window.addEventListener('load', () => {
    lucide.createIcons();
    initChart();
    updatePhaseUI('A');
    populateDataTable();
    
    // Register slider listener
    const slider = document.getElementById('player-slider');
    if (slider) slider.max = speechPeriodData.length - 1;
    
    // Register media sync drag-and-drop & event listeners
    initMediaSync();
    
    // Initialize playback timeline to index 0 cleanly
    jumpToTimelineIndex(0);
});

// Tab switching controller
function switchTab(tabId) {
    const tabs = ['dashboard', 'manuscript', 'data'];
    tabs.forEach(t => {
        const content = document.getElementById(`tab-content-${t}`);
        const btn = document.getElementById(`tab-btn-${t}`);
        
        if (t === tabId) {
            content.classList.remove('hidden');
            btn.className = "px-4 py-1.5 text-xs font-semibold rounded-md transition-all duration-200 bg-indigo-600 text-white shadow";
        } else {
            content.classList.add('hidden');
            btn.className = "px-4 py-1.5 text-xs font-semibold rounded-md transition-all duration-200 text-slate-400 hover:text-slate-200";
        }
    });
    
    // Re-render chart if switching back to dashboard to ensure no sizing glitches
    if (tabId === 'dashboard' && chartInstance) {
        setTimeout(() => chartInstance.updateOptions({}), 100);
    }
}

