// Initialize ApexCharts Engine
function initChart() {
    // Initially only draw up to the speech start time (10:25:00 WIB)
    const speechStartWibTime = "10:25:00";
    const startFullIndex = ihsgData.findIndex(x => x.time === speechStartWibTime);
    const initialPrices = ihsgData.slice(0, startFullIndex + 1).map(x => x.close);
    const initialCategories = ihsgData.slice(0, startFullIndex + 1).map(x => x.time);
    
    const options = {
        series: [{
            name: 'IHSG Index',
            data: initialPrices
        }],
        chart: {
            type: 'line',
            height: 550,
            foreColor: '#94a3b8',
            toolbar: {
                show: false
            },
            events: {
                markerClick: function(event, chartContext, { dataPointIndex }) {
                    const clickedItem = ihsgData[dataPointIndex];
                    if (clickedItem && clickedItem.in_speech) {
                        const speechIdx = speechPeriodData.findIndex(x => x.time === clickedItem.time);
                        if (speechIdx !== -1) {
                            jumpToTimelineIndex(speechIdx);
                        }
                    }
                }
            }
        },
        colors: ['#6366f1'],
        stroke: {
            width: 3,
            curve: 'smooth'
        },
        grid: {
            borderColor: '#1e293b',
            strokeDashArray: 4,
            padding: {
                left: 10,
                right: 10
            }
        },
        xaxis: {
            type: 'category',
            categories: initialCategories,
            labels: {
                show: true,
                rotate: 0,
                hideOverlappingLabels: true,
                style: {
                    fontSize: '10px'
                },
                formatter: function(val) {
                    if (val && typeof val === 'string') {
                        return val.substring(0, 5); // hh:mm format
                    }
                    return val || '';
                }
            },
            axisBorder: {
                show: false
            },
            axisTicks: {
                show: false
            }
        },
        yaxis: {
            min: 6200,
            max: 6470,
            tickAmount: 6,
            labels: {
                style: {
                    fontSize: '10px'
                },
                formatter: function(val) {
                    return (val !== undefined && val !== null) ? val.toFixed(0) : '';
                }
            }
        },
        tooltip: {
            theme: 'dark',
            x: {
                show: true
            },
            y: {
                formatter: function(val, { dataPointIndex }) {
                    const item = ihsgData[dataPointIndex];
                    if (!item) return val !== undefined && val !== null ? val.toFixed(2) : '';
                    const retPct = typeof item.return_pct === 'number' ? item.return_pct.toFixed(2) : item.return_pct;
                    const retText = item.return_pct >= 0 ? `+${retPct}%` : `${retPct}%`;
                    return `${val !== undefined && val !== null ? val.toFixed(2) : ''} (${retText})`;
                }
            },
            custom: function({ series, seriesIndex, dataPointIndex, w }) {
                const item = ihsgData[dataPointIndex];
                if (!item) return '';
                const retPct = typeof item.return_pct === 'number' ? item.return_pct.toFixed(2) : item.return_pct;
                const retColor = item.return_pct >= 0 ? 'text-emerald-400' : 'text-rose-400';
                const retText = item.return_pct >= 0 ? `+${retPct}%` : `${retPct}%`;
                
                let subtitleOverlay = "";
                if (item.in_speech && item.text) {
                    subtitleOverlay = `
                        <div class="mt-2 pt-2 border-t border-slate-700/60">
                            <span class="text-[9px] text-indigo-400 uppercase tracking-wider block font-bold">Active Quote Overlay:</span>
                            <span class="text-[11px] italic text-slate-300">"${item.text.substring(0, 100)}..."</span>
                        </div>
                    `;
                }
                
                return `
                    <div class="p-3 bg-slate-900 border border-slate-800 rounded-lg text-xs leading-normal">
                        <div class="font-bold text-white flex items-center justify-between gap-4">
                            <span>Time: ${item.time} WIB</span>
                            <span class="text-[10px] bg-slate-800 px-1.5 py-0.5 rounded text-slate-400 font-mono">Index</span>
                        </div>
                        <div class="mt-1 flex items-baseline gap-2">
                            <span class="text-sm font-bold text-white">${item.close !== undefined && item.close !== null ? item.close.toFixed(2) : ''}</span>
                            <span class="font-semibold text-[10px] ${retColor}">${retText}</span>
                        </div>
                        ${subtitleOverlay}
                    </div>
                `;
            }
        },
        annotations: {
            xaxis: [],
            points: []
        }
    };

    chartInstance = new ApexCharts(document.querySelector("#ihsg-main-chart"), options);
    chartInstance.render();
}

// Select phase explicitly via buttons
function selectPhase(phaseId) {
    activePhase = phaseId;
    updatePhaseUI(phaseId);
    
    let targetTime = "10:25:00";
    if (phaseId === 'B') targetTime = "11:06:00";
    else if (phaseId === 'C') targetTime = "11:22:00";
    else if (phaseId === 'D') targetTime = "11:34:00";
    else if (phaseId === 'E') targetTime = "11:53:00";
    
    const speechIdx = speechPeriodData.findIndex(x => x.time === targetTime);
    if (speechIdx !== -1) {
        jumpToTimelineIndex(speechIdx);
    }
}

